import { useEffect, useState, useCallback } from "react";
import { Card, CardContent } from "@/components/ui/card";
import { Button } from "@/components/ui/button";
import { Badge } from "@/components/ui/badge";
import {
  Tabs,
  TabsContent,
  TabsList,
  TabsTrigger,
} from "@/components/ui/tabs";

import { apiClient, authService } from "@/App";
import { toast } from "sonner";

import {
  Users,
  UsersRound,
  CalendarCheck,
  ClipboardCheck,
  CheckCircle,
  XCircle,
  AlertTriangle,
  GraduationCap,
  CreditCard,
  Loader2,
} from "lucide-react";

const Dashboard = () => {
  const [stats, setStats] = useState(null);

  const [pending, setPending] = useState({
    students: [],
    results: [],
    attendance: [],
    payments: [],
    announcements: [],
    total: 0,
  });

  const [loading, setLoading] = useState(true);
  const [approvalLoading, setApprovalLoading] = useState(false);

  // =========================
  // SAFE USER FIX
  // =========================
  const rawUser = authService.getUser() || {};

  const normalizeRole = (role) => {
    if (!role) return "";

    const r = role.toString().toLowerCase();

    if (r === "admin") return "school_admin";
    if (r === "schooladmin") return "school_admin";
    if (r === "superadmin") return "super_admin";

    return r;
  };

  const user = {
    ...rawUser,
    role: normalizeRole(rawUser.role),
  };

  const isAdmin = user.role === "school_admin";

  // =========================
  // FETCH DASHBOARD DATA
  // =========================
  const fetchDashboardData = useCallback(async () => {
    try {
      setLoading(true);

      // =========================
      // FETCH STATS SAFELY
      // =========================
      try {
        const statsRes = await apiClient.get("/dashboard/stats");

        setStats(statsRes?.data || {});
      } catch (err) {
        console.error("Stats error:", err);

        setStats({
          total_students: 0,
          total_staff: 0,
          present_today: 0,
          pending_approvals: 0,
        });
      }

      // =========================
      // ADMIN PENDING
      // =========================
      if (isAdmin) {
        try {
          const pendingRes = await apiClient.get("/admin/pending");

          setPending({
            students: pendingRes?.data?.students || [],
            results: pendingRes?.data?.results || [],
            attendance: pendingRes?.data?.attendance || [],
            payments: pendingRes?.data?.payments || [],
            announcements: pendingRes?.data?.announcements || [],
            total: pendingRes?.data?.total || 0,
          });
        } catch (err) {
          console.error("Pending approval error:", err);

          setPending({
            students: [],
            results: [],
            attendance: [],
            payments: [],
            announcements: [],
            total: 0,
          });
        }
      }
    } catch (error) {
      console.error("Dashboard error:", error);

      toast.error("Failed to load dashboard");
    } finally {
      setLoading(false);
    }
  }, [isAdmin]);

  useEffect(() => {
    fetchDashboardData();
  }, [fetchDashboardData]);

  // =========================
  // APPROVAL HANDLER
  // =========================
  const handleApproval = async (
    itemType,
    itemId,
    action
  ) => {
    try {
      setApprovalLoading(true);

      await apiClient.patch(
        `/admin/approve/${itemType}/${itemId}`,
        {
          action,
        }
      );

      toast.success(
        `${itemType} ${action} successfully`
      );

      await fetchDashboardData();
    } catch (error) {
      console.error("Approval error:", error);

      toast.error(
        error?.response?.data?.detail ||
          `Failed to ${action} ${itemType}`
      );
    } finally {
      setApprovalLoading(false);
    }
  };

  // =========================
  // STATS
  // =========================
  const statCards = [
    {
      title: "Students",
      value: stats?.total_students || 0,
      icon: Users,
      accent: "emerald",
    },
    {
      title: "Staff",
      value: stats?.total_staff || 0,
      icon: UsersRound,
      accent: "cyan",
    },
    {
      title: "Attendance",
      value: stats?.present_today || 0,
      icon: CalendarCheck,
      accent: "violet",
    },
    {
      title: "Pending",
      value: stats?.pending_approvals || 0,
      icon: ClipboardCheck,
      accent: "amber",
    },
  ];

  const accentMap = {
    emerald: {
      bg: "bg-emerald-500/15",
      text: "text-emerald-400",
      border: "border-emerald-500/20",
    },

    cyan: {
      bg: "bg-cyan-500/15",
      text: "text-cyan-400",
      border: "border-cyan-500/20",
    },

    violet: {
      bg: "bg-violet-500/15",
      text: "text-violet-400",
      border: "border-violet-500/20",
    },

    amber: {
      bg: "bg-amber-500/15",
      text: "text-amber-400",
      border: "border-amber-500/20",
    },
  };

  // =========================
  // LOADING
  // =========================
  if (loading) {
    return (
      <div className="flex items-center justify-center h-[70vh]">
        <div className="flex items-center gap-3 text-slate-400">
          <Loader2 className="w-5 h-5 animate-spin" />
          <span>Loading dashboard...</span>
        </div>
      </div>
    );
  }

  // =========================
  // TAB CONFIG
  // =========================
  const tabs = [
    {
      key: "students",
      label: "Students",
      items: pending.students,
      itemType: "student",
    },
    {
      key: "results",
      label: "Results",
      items: pending.results,
      itemType: "result",
    },
    {
      key: "attendance",
      label: "Attendance",
      items: pending.attendance,
      itemType: "attendance",
    },
    {
      key: "payments",
      label: "Payments",
      items: pending.payments,
      itemType: "payment",
    },
    {
      key: "announcements",
      label: "Announcements",
      items: pending.announcements,
      itemType: "announcement",
    },
  ];

  const firstAvailableTab =
    tabs.find((t) => t.items?.length > 0)?.key ||
    "students";

  return (
    <div className="space-y-8">

     {/* HEADER SECTION */}
<div className="space-y-4">

  {/* HEADER */}
  <div>
    <h1 className="text-3xl font-bold text-white">
      Dashboard Overview
    </h1>

    <p className="text-slate-400 mt-1">
      Welcome back {user?.full_name || "User"}
    </p>
  </div>

  {/* SCHOOL FINGERPRINT (ONLY SCHOOL ADMIN) */}
  {isAdmin && user?.school_code && (
    <div className="bg-[#1A2332] border border-[#1E293B] rounded-xl p-4 space-y-3">

      <p className="text-[10px] uppercase text-slate-400">
        School Fingerprint
      </p>

      {(() => {
        const initials = (user?.school_name || "")
          .split(" ")
          .filter(Boolean)
          .map(w => w[0])
          .join("")
          .toUpperCase();

        const fingerprint = `${initials}-${user.school_code}`;

        const inviteLink =
          `${window.location.origin}/join/` +
          `${(user?.school_name || "").replace(/\s+/g, "")}-${user.school_code}`;

        const copy = async (text) => {
          try {
            await navigator.clipboard.writeText(text);
            toast.success("Copied to clipboard");
          } catch (err) {
            toast.error("Copy failed");
          }
        };

        return (
          <div className="space-y-3">

            {/* FINGERPRINT */}
            <div className="flex items-center justify-between">
              <span className="text-emerald-400 font-semibold">
                {fingerprint}
              </span>

              <Button
                size="sm"
                variant="outline"
                onClick={() => copy(fingerprint)}
              >
                Copy
              </Button>
            </div>

            {/* INVITE LINK */}
            <div className="flex items-center justify-between gap-2">
              <span className="text-xs text-slate-400 break-all">
                {inviteLink}
              </span>

              <Button
                size="sm"
                variant="outline"
                onClick={() => copy(inviteLink)}
              >
                Copy
              </Button>
            </div>

          </div>
        );
      })()}

    </div>
  )}

</div>
      {/* STATS */}
      <div className="grid grid-cols-1 md:grid-cols-2 xl:grid-cols-4 gap-5">
        {statCards.map((stat, index) => {
          const Icon = stat.icon;
          const accent = accentMap[stat.accent];

          return (
            <Card
              key={index}
              className={`bg-[#1A2332] ${accent.border}`}
            >
              <CardContent className="p-5">

                <div className="flex items-center justify-between mb-4">
                  <div>
                    <p className="text-sm text-slate-400">
                      {stat.title}
                    </p>

                    <h2 className="text-3xl font-bold text-white mt-2">
                      {stat.value}
                    </h2>
                  </div>

                  <div
                    className={`${accent.bg} p-3 rounded-xl`}
                  >
                    <Icon
                      className={`w-5 h-5 ${accent.text}`}
                    />
                  </div>
                </div>

              </CardContent>
            </Card>
          );
        })}
      </div>

      {/* ADMIN APPROVALS */}
      {isAdmin && (
        <Card className="bg-[#1A2332] border-[#1E293B]">
          <CardContent className="p-6">

            <div className="flex items-center gap-3 mb-6">
              <AlertTriangle className="w-5 h-5 text-amber-400" />

              <div>
                <h2 className="text-lg font-semibold text-white">
                  Pending Approvals
                </h2>

                <p className="text-sm text-slate-400">
                  {pending.total} pending items
                </p>
              </div>
            </div>

            {pending.total === 0 ? (
              <div className="text-center py-10">
                <CheckCircle className="w-10 h-10 text-emerald-400 mx-auto mb-3" />

                <p className="text-emerald-400 font-medium">
                  No pending approvals
                </p>
              </div>
            ) : (
              <Tabs
                defaultValue={firstAvailableTab}
                className="space-y-5"
              >

                <TabsList className="bg-[#0F172A] border border-[#1E293B] flex flex-wrap h-auto">

                  {tabs.map((tab) => {
                    if (!tab.items?.length) return null;

                    return (
                      <TabsTrigger
                        key={tab.key}
                        value={tab.key}
                        className="data-[state=active]:bg-emerald-600/20 data-[state=active]:text-emerald-400"
                      >
                        {tab.label} ({tab.items.length})
                      </TabsTrigger>
                    );
                  })}

                </TabsList>

                {tabs.map((tab) => {
                  if (!tab.items?.length) return null;

                  return (
                    <TabsContent
                      key={tab.key}
                      value={tab.key}
                    >

                      <div className="space-y-3">

                        {tab.items.map((item) => (
                          <div
                            key={item.id}
                            className="bg-[#0F172A] border border-[#1E293B] rounded-xl p-4 flex flex-col lg:flex-row lg:items-center lg:justify-between gap-4"
                          >

                            <div className="space-y-1">

                              {/* STUDENTS */}
                              {tab.key === "students" && (
                                <>
                                  <p className="font-semibold text-white">
                                    {item.full_name || "Unnamed Student"}
                                  </p>

                                  <p className="text-sm text-slate-400">
                                    {item.class_name || "No class"}
                                  </p>
                                </>
                              )}

                              {/* RESULTS */}
                              {tab.key === "results" && (
                                <>
                                  <div className="flex items-center gap-2 flex-wrap">
                                    <p className="font-semibold text-white">
                                      {item.subject}
                                    </p>

                                    <Badge>
                                      {item.grade}
                                    </Badge>

                                    <span className="text-slate-400 text-sm">
                                      {item.marks} marks
                                    </span>
                                  </div>
                                </>
                              )}

                              {/* ATTENDANCE */}
                              {tab.key === "attendance" && (
                                <>
                                  <p className="font-semibold text-white">
                                    Attendance Record
                                  </p>

                                  <p className="text-sm text-slate-400">
                                    {item.date} — {item.status}
                                  </p>
                                </>
                              )}

                              {/* PAYMENTS */}
                              {tab.key === "payments" && (
                                <>
                                  <p className="font-semibold text-white">
                                    KES {item.amount || 0}
                                  </p>

                                  <p className="text-sm text-slate-400">
                                    {item.payment_type || "Payment"}
                                  </p>
                                </>
                              )}

                              {/* ANNOUNCEMENTS */}
                              {tab.key === "announcements" && (
                                <>
                                  <p className="font-semibold text-white">
                                    {item.title}
                                  </p>

                                  <p className="text-sm text-slate-400">
                                    Announcement awaiting approval
                                  </p>
                                </>
                              )}

                              <p className="text-xs text-slate-500 pt-1">
                                Submitted by{" "}
                                {item?.submitter?.full_name ||
                                  "Unknown"}
                              </p>

                            </div>

                            <div className="flex gap-2">

                              <Button
                                disabled={approvalLoading}
                                onClick={() =>
                                  handleApproval(
                                    tab.itemType,
                                    item.id,
                                    "approved"
                                  )
                                }
                                className="bg-emerald-600 hover:bg-emerald-500"
                              >
                                <CheckCircle className="w-4 h-4 mr-2" />
                                Approve
                              </Button>

                              <Button
                                disabled={approvalLoading}
                                variant="destructive"
                                onClick={() =>
                                  handleApproval(
                                    tab.itemType,
                                    item.id,
                                    "rejected"
                                  )
                                }
                              >
                                <XCircle className="w-4 h-4 mr-2" />
                                Reject
                              </Button>

                            </div>

                          </div>
                        ))}

                      </div>

                    </TabsContent>
                  );
                })}

              </Tabs>
            )}

          </CardContent>
        </Card>
      )}

      {/* NON ADMIN */}
      {!isAdmin && (
        <Card className="bg-[#1A2332] border-[#1E293B]">
          <CardContent className="p-8 text-center">

            <GraduationCap className="w-10 h-10 text-emerald-400 mx-auto mb-3" />

            <h2 className="text-xl font-semibold text-white mb-2">
              Welcome to Smart-M Hub
            </h2>

            <p className="text-slate-400">
              Your dashboard modules are available from the sidebar menu.
            </p>

          </CardContent>
        </Card>
      )}

    </div>
  );
};

export default Dashboard;
